import signal

class TimeoutError(Exception):
    pass

def timeout_handler(signum, frame):
    raise TimeoutError("代码执行超时")

def run_code_with_timeout(code_string, timeout_seconds=10):
    """带超时控制的代码执行（仅 Linux/Mac）"""
